<?php
function solveCase(string $s, array $words): array { if (!$words) return []; $wlen = strlen($words[0]); $total = $wlen * count($words); $target = $words; sort($target); $ans = []; for ($i = 0; $i + $total <= strlen($s); $i++) { $parts = []; for ($j = 0; $j < count($words); $j++) $parts[] = substr($s, $i + $j * $wlen, $wlen); sort($parts); if ($parts == $target) $ans[] = $i; } return $ans; }
$lines = preg_split('/\r?\n/', trim(stream_get_contents(STDIN))); if (!$lines || $lines[0] === '') exit; $idx = 0; $t = intval(trim($lines[$idx++])); $out = []; for ($tc=0; $tc<$t; $tc++) { $s = $idx < count($lines) ? $lines[$idx++] : ''; $m = $idx < count($lines) ? intval(trim($lines[$idx++])) : 0; $words = []; for ($i=0; $i<$m; $i++) $words[] = $idx < count($lines) ? $lines[$idx++] : ''; $out[] = '[' . implode(',', solveCase($s, $words)) . ']'; } echo implode("\n", $out);
